-                                     SimplifyQuery(I.getDataLayout()));
-          };
-
-          if (CheckAndMask()) {
-            replaceWithPopCount(I, Root);
-            return true;
-          }
-        }
-      }
-    }
-  }
+  if (!match(Op0, m_Mul(m_Value(MulOp0), m_SpecificInt(Mask01))) ||
+      !match(Op1, m_SpecificInt(Len - 8)))
+    return false;

-  return false;
+  Value *Root = matchPopCountBytes(MulOp0, Len, I.getDataLayout());
+  if (!Root)
+    return false;
+
+  replaceWithPopCount(I, Root);
+  return true;
 }

